mapper.select:
SELECT DISTINCT menu_name
FROM REVIEW_MENU_TBL
WHERE review_no IN (SELECT review_no
                   FROM REVIEW_TBL
                   WHERE rest_no = #{restNo}
);

SELECT r.review_no, m.member_name AS writer, m.member_thumb AS writer_thumb, r.rating, r.review_content, r.visit_date
FROM REVIEW_TBL r INNER JOIN MEMBER_TBL m ON r.member_id = m.member_id WHERE rest_no = #{restNo} AND review_status = 0 ORDER BY r.visit_date DESC
LIMIT #{size} OFFSET #{offset}

